#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);
        for (int i = 0; i + 1 < N; i += 2) {
            long long tmp = a[i]; a[i] = a[i+1]; a[i+1] = tmp;
        }
        for (int i = 0; i < N; ++i) {
            printf("%lld", a[i]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
        free(a);
    }
    return 0;
}

